func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		assignIdx int
		costDelta float64
	}
	const EMPTY_ASSIGN_IDX = MAXASSIGNS - 1

	for jj := 0; jj < len(oris); jj++ {
		bestCandidate := candidate{assignIdx: -1, costDelta: 1e18}
		orderID := total_ship + jj

		maxCheckIdx := dispatch.AssignsLen
		if maxCheckIdx == 0 {
			goto fallbackEmpty
		}

		for idx := 0; idx <= maxCheckIdx; idx++ {
			actualIdx := idx
			if idx == maxCheckIdx {
				if dispatch.AssignsLen >= MAXASSIGNS {
					continue
				}
				actualIdx = EMPTY_ASSIGN_IDX
			} else {
				if actualIdx >= MAXASSIGNS {
					continue
				}
			}

			savedCost := dispatch.Assigns[actualIdx].Cost
			savedStateExists := false
			if idx == maxCheckIdx && actualIdx >= dispatch.AssignsLen {
				dispatch.Assigns[actualIdx] = Assign{}
			} else {
				savedStateExists = true
			}

			ok := dispatch.Assigns[actualIdx].AddShip(orderID, oris[jj], dess[jj])
			if !ok {
				if savedStateExists {
					dispatch.Assigns[actualIdx].Cost = savedCost
				}
				continue
			}
			oldAssignCost := savedCost
			dispatch.Assigns[actualIdx].GenRoute()
			newAssignCost := dispatch.Assigns[actualIdx].Cost
			delta := newAssignCost - oldAssignCost

			dispatch.Assigns[actualIdx].RemoveShip(orderID)
			if savedStateExists {
				dispatch.Assigns[actualIdx].Cost = savedCost
				dispatch.Assigns[actualIdx].GenRoute()
			} else {
				dispatch.Assigns[actualIdx] = Assign{}
			}

			if delta >= 0 && delta < bestCandidate.costDelta {
				bestCandidate.assignIdx = actualIdx
				bestCandidate.costDelta = delta
			}
		}

		if bestCandidate.assignIdx != -1 {
			targetIdx := bestCandidate.assignIdx
			if targetIdx == EMPTY_ASSIGN_IDX || targetIdx >= dispatch.AssignsLen {
				if dispatch.AssignsLen >= MAXASSIGNS {
					goto fallbackEmpty
				}
				targetIdx = dispatch.AssignsLen
				dispatch.Assigns[targetIdx] = Assign{}
				dispatch.AssignsLen++
			}
			success := dispatch.Assigns[targetIdx].AddShip(orderID, oris[jj], dess[jj])
			if success {
				dispatch.Assigns[targetIdx].GenRoute()
				continue
			}
		}

	fallbackEmpty:
		if dispatch.AssignsLen >= MAXASSIGNS {
			minLoadIdx := -1
			minLoadVal := 1<<31 - 1
			for i := 0; i < dispatch.AssignsLen; i++ {
				ld := 0
				if dispatch.Assigns[i].StationCurrent.Load > 0 {
					ld = dispatch.Assigns[i].StationCurrent.Load
				}
				if ld < minLoadVal {
					minLoadVal = ld
					minLoadIdx = i
				}
			}
			if minLoadIdx >= 0 {
				dispatch.Assigns[minLoadIdx].AddShip(orderID, oris[jj], dess[jj])
				dispatch.Assigns[minLoadIdx].GenRoute()
			}
			continue
		}
		newIdx := dispatch.AssignsLen
		dispatch.Assigns[newIdx].AddShip(orderID, oris[jj], dess[jj])
		dispatch.Assigns[newIdx].GenRoute()
		dispatch.AssignsLen++
	}

	dispatch.RenewnTotalCost()
	return dispatch

