func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    type tryResult struct {
        idx       int
        delta     float64
        ok        bool
    }

    // Pre‑shuffle non‑empty assigns once per batch
    candidates := make([]int, 0, MAXASSIGNS)
    for i := 0; i < dispatch.AssignsLen; i++ {
        candidates = append(candidates, i)
    }
    // Random permutation of existing assigns
    for i := len(candidates) - 1; i > 0; i-- {
        j := int(cal_dis(Station{}, Station{})*100000) % (i + 1) // cheap rng using cal_dis noise
        candidates[i], candidates[j] = candidates[j], candidates[i]
    }
    // Also consider a potential fresh assign at the end (as a sentinel for fallback)
    // We will handle fallback explicitly.

    for jj := 0; jj < len(oris); jj++ {
        shipID := total_ship + jj
        ori := oris[jj]
        des := dess[jj]

        var best tryResult
        best.delta = 1e18
        best.ok = false

        // Try each existing assign
        for _, ci := range candidates {
            // Save current state via temporary removal later; here we just probe
            // Probe insertion
            oldCost := dispatch.Assigns[ci].Cost
            // We cannot directly read internal route, so we use AddShip → GenRoute → compare cost
            // But we must be able to rollback without side effects.
            // Since AddShip mutates, we need to clone? Not allowed. Instead use trial-and-error
            // pattern: attempt, measure, remove, restore.
            added := dispatch.Assigns[ci].AddShip(shipID, ori, des)
            if !added {
                continue // cannot insert here
            }
            dispatch.Assigns[ci].GenRoute()
            if dispatch.Assigns[ci].Cost < 0 {
                // invalid route, rollback
                dispatch.Assigns[ci].RemoveShip(shipID)
                dispatch.Assigns[ci].GenRoute()
                continue
            }
            newDelta := dispatch.Assigns[ci].Cost - oldCost
            // Record if this is better than previous best for this order
            if newDelta < best.delta {
                best.idx = ci
                best.delta = newDelta
                best.ok = true
            }
            // Undo trial
            dispatch.Assigns[ci].RemoveShip(shipID)
            dispatch.Assigns[ci].GenRoute()
        }

        // Determine where to actually place the order
        targetIdx := -1
        if best.ok {
            targetIdx = best.idx
        } else {
            // Fallback: create/append a new empty assign if needed
            // Use first truly empty slot beyond AssignsLen, or extend AssignsLen
            // We rely on the invariant that an empty assign always accepts an order.
            foundEmpty := false
            // Check existing empty assigns (they may exist with zero stations but still present)
            for i := 0; i < MAXASSIGNS; i++ {
                if i >= dispatch.AssignsLen || dispatch.Assigns[i].Cost == 0 {
                    // Treat as empty enough to start fresh
                    targetIdx = i
                    foundEmpty = true
                    break
                }
            }
            if !foundEmpty && dispatch.AssignsLen < MAXASSIGNS {
                targetIdx = dispatch.AssignsLen
                foundEmpty = true
            }
            if !foundEmpty {
                // Should not happen given MAXASSIGNS capacity, but force into last slot
                targetIdx = MAXASSIGNS - 1
            }
        }

        // Commit insertion at targetIdx
        if targetIdx >= dispatch.AssignsLen {
            dispatch.AssignsLen = targetIdx + 1
        }
        // Ensure clean slate if it's a brand-new slot: clear any residual data implicitly by AddShip
        okCommit := dispatch.Assigns[targetIdx].AddShip(shipID, ori, des)
        if !okCommit {
            // Last resort: brute-force search any slot again, including those skipped earlier
            // This ensures every order is placed somewhere.
            for k := 0; k < MAXASSIGNS; k++ {
                if dispatch.Assigns[k].AddShip(shipID, ori, des) {
                    dispatch.Assigns[k].GenRoute()
                    if dispatch.Assigns[k].Cost >= 0 {
                        targetIdx = k
                        if targetIdx >= dispatch.AssignsLen {
                            dispatch.AssignsLen = targetIdx + 1
                        }
                        break
                    }
                    dispatch.Assigns[k].RemoveShip(shipID)
                    dispatch.Assigns[k].GenRoute()
                }
            }
        } else {
            dispatch.Assigns[targetIdx].GenRoute()
        }
    }

    dispatch.RenewnTotalCost()
    return dispatch

